import { Context, Data, Effect, Layer } from 'effect'
class AppError extends Data.TaggedError('AppError')<{ message: string }> {}
class Config extends Context.Tag('Config')<Config, { readonly apiKey: string }>() {}
const ConfigLive = Layer.succeed(Config, { apiKey: 'secret' })
const program = Effect.gen(function*() {
  const config = yield* Config
  return yield* Effect.tryPromise({ try: () => fetch(config.apiKey), catch: () => new AppError({ message: 'failed' }) })
}).pipe(Effect.catchAll((e) => Effect.log(e.message)))
Effect.runPromise(program.pipe(Effect.provide(ConfigLive)))
